import { NewDropdownMenu } from ':components/NewDropdownMenu';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React from 'react';

import './CountrySelect.scss';
import { Divider } from ':components/Divider';
import { IconButton } from ':components/IconButton';
import { Country } from './Countries.const';
import { CountrySelectItem } from './CountrySelectItem/CountrySelectItem';
import { Flag } from './Flag';

type CountrySelectProps = {
	isOpen: boolean;
	handleSetOpen: (arg: boolean) => void;
	targetElement: React.RefObject<HTMLElement>;
	value: Country;
	options: any;
	onClick: (event, value: Country) => void;
};

export const CountrySelect: React.FC<CountrySelectProps> = ({
	isOpen,
	handleSetOpen,
	targetElement,
	value,
	options,
	onClick,
}) => {
	const { RU, ...rest } = options;

	return (
		<>
			<div className="dsb_phoneinput__country" onClick={() => handleSetOpen(!isOpen)}>
				<Flag value={value} />
				<IconButton
					iconName={isOpen ? Icons.NavArrowUp : Icons.NavArrowDown}
					className="dsb_phoneinput__country__iconbutton"
				/>
				<Divider type="vertical" className="dsb_phoneinput__country__divider" />
			</div>
			{isOpen && (
				<NewDropdownMenu
					verticalOffset={1}
					targetElement={targetElement}
					isOpen={isOpen}
					handleSetOpen={handleSetOpen}
					widthMode="widthParent"
				>
					<div className="dsb_phoneinput__country__dropdown">
						{RU && <CountrySelectItem value={RU} key={RU.nameCode} onClick={onClick} />}
						{Object.keys(rest).map(country => (
							<CountrySelectItem key={options[country].nameCode} value={options[country]} onClick={onClick} />
						))}
					</div>
				</NewDropdownMenu>
			)}
		</>
	);
};
